100	/*
101	 * njs_prop_handler_t operates as a property getter/setter or delete handler.
102	 * - retval != NULL && setval == NULL - GET context.
103	 * - retval != NULL && setval != NULL - SET context.
104	 * - retval == NULL - DELETE context.
105	 *
106	 * njs_prop_handler_t is expected to return:
107	 *   NJS_OK - handler executed successfully;
108	 *   NJS_DECLINED - handler was applied to inappropriate object, retval
109	 *   contains undefined value;
110	 *   NJS_ERROR - some error, njs_vm_exception_get(vm) can be used to get
111	 *   the exception value.
112	 */
113	typedef njs_int_t (*njs_prop_handler_t) (njs_vm_t *vm, njs_object_prop_t *prop,
114	    uint32_t atom_id, njs_value_t *value, njs_value_t *setval,
115	    njs_value_t *retval);
